CODE_EXAMPLE:
// Before
class IntervalWindow {
  Interval interval;
}

// After
class IntervalWindow {
  Interval interval;
  int start;
  int length;
  void updateInterval() {
    interval.setStart(start);
    interval.setLength(length);
  }
}

UNIT_TEST_EXAMPLE:
@Test
public void testDuplicateObservedData() {
  Interval interval = new Interval(5, 10);
  IntervalWindow window = new IntervalWindow(interval);

  assertEquals(5, window.getStart());
  assertEquals(10, window.getLength());
}
